import java.util.function.*;
public class Closure {
    public static void main(String[] args) {
        int base = 100;  // effectively final
        Function<Integer,Integer> adder = x -> x + base;
        System.out.println(adder.apply(5));
        System.out.println(adder.apply(20));
        BiFunction<Integer,Integer,Integer> mul = (a,b) -> a * b + base;
        System.out.println(mul.apply(3, 4));
    }
}
